import { Lesson } from './types';
import { createLesson } from './data_helpers';

export const porLessonsB1: Lesson[] = [
  createLesson('g2-por-b1-l1', 'L1: Retomada e Aprofundamento — Linguagem e Texto', 'portugues', 'Revisão do conceito de texto: unidade de sentido com coesão e coerência. Texto e discurso: o texto como prática social. Formação discursiva: ideologia, posição social e produção de sentido. Polifonia: vozes no texto (Bakhtin). Intertextualidade e interdiscursividade. Texto e contexto de produção: autor, época, público. Leitura crítica: não existe texto neutro — todo texto tem uma perspectiva. O ENEM avalia a leitura crítica e contextualizada.', ['O que significa dizer que um texto é uma "prática social"? Dê exemplos.', 'Identifique as "vozes" (polifonia) presentes neste editorial de jornal.']),
  createLesson('g2-por-b1-l2', 'L2: Realismo Português — Eça de Queirós', 'portugues', 'Realismo em Portugal (a partir de 1865): Conferências do Casino (1871). Eça de Queirós: principal nome. Obras: "O Crime do Padre Amaro" (crítica ao clero), "O Primo Basílio" (adultério burguês, paralelo com Madame Bovary), "Os Maias" (decadência da aristocracia portuguesa). Características: crítica social, objetividade, determinismo, análise psicológica, ironia fina. Comparação com o Realismo brasileiro (Machado vs. Eça).', ['Compare Eça de Queirós e Machado de Assis: semelhanças e diferenças no estilo realista.', 'Analise a crítica social em um trecho de Eça de Queirós.']),
  createLesson('g2-por-b1-l3', 'L3: Simbolismo no Brasil e em Portugal', 'portugues', 'Simbolismo (1893-1902 no Brasil): reação ao Realismo/Naturalismo. Características: espiritualismo, subjetivismo, musicalidade, sugestão (não descrição), uso do símbolo e do estado de alma. Sinestesia e aliteração. Brasil: Cruz e Sousa ("Broquéis") — negritude e simbolismo; Alphonsus de Guimaraens — religiosidade mariana. Portugal: Antero de Quental, Cesário Verde (pré-simbolista). Relação entre Simbolismo e Decadentismo europeu.', ['Analise a musicalidade e o uso de símbolos neste poema de Cruz e Sousa.', 'O que representa a escolha de Cruz e Sousa pelo Simbolismo sendo ele negro no Brasil escravocrata?']),
  createLesson('g2-por-b1-l4', 'L4: Fernando Pessoa e o Modernismo Português', 'portugues', 'Fernando Pessoa: maior poeta português do século XX. Heterônimos: Alberto Caeiro (paganismo, sensacionismo bucólico), Ricardo Reis (neoclassicismo, estoicismo), Álvaro de Campos (futurismo, sensacionismo moderno — "Ode Triunfal"), ortônimo Fernando Pessoa ("Mensagem", saudade, destino de Portugal). "Fingir é conhecer-se." Presença de Pessoa no ENEM brasileiro. Excerto análise: "Autopsicografia", "Mar Português".', ['Analise "Autopsicografia" de Fernando Pessoa: o que ele diz sobre o ato de fingir/criar?', 'Compare dois heterônimos de Pessoa: que filosofias de vida expressam?']),
  createLesson('g2-por-b1-l5', 'L5: Vanguardas Europeias e o Modernismo Brasileiro', 'portugues', 'Vanguardas (início séc. XX): futurismo (Marinetti — velocidade, máquina), expressionismo (emoção intensa, distorção), cubismo (fragmentação), dadaísmo (destruição do sentido), surrealismo (inconsciente, sonho — Breton). Como influenciaram o Modernismo brasileiro (1922): liberdade formal, experimentação, ruptura com a tradição. A Semana de Arte Moderna revisitada. Relação vanguarda europeia × modernismo nacional: cópia ou recriação?', ['Identifique características de uma vanguarda europeia neste poema modernista brasileiro.', 'Em que o Modernismo brasileiro é diferente das vanguardas europeias?']),
  createLesson('g2-por-b1-l6', 'L6: Morfossintaxe — Revisão e Aprofundamento', 'portugues', 'Revisão aprofundada de morfossintaxe. Transitividade verbal e predicação: VTD (objeto direto), VTI (objeto indireto + preposição), VTDI (ambos), VI, predicativos. Vozes verbais: ativa, passiva analítica (ser + particípio), passiva sintética (se), voz reflexiva. Transformações: ativo ↔ passivo. Ergatividade. Particípio: regular e irregular. Verbos com dois particípios (abundantes): pago/pagado, ganho/ganhado, etc. Prática com textos literários.', ['Transforme estas frases da voz ativa para a voz passiva e vice-versa.', 'Identifique os verbos abundantes neste texto e explique o uso de cada particípio.']),
  createLesson('g2-por-b1-l7', 'L7: Semântica — Sentido das Palavras', 'portugues', 'Semântica: estudo do significado. Denotação (significado literal, dicionário) e conotação (significado figurado, contextual). Polissemia: uma palavra com vários sentidos. Homonímia: palavras iguais com significados diferentes (homófonos: mesma pronúncia; homógrafos: mesma escrita; homônimos perfeitos: iguais em tudo). Paronímia: palavras semelhantes na forma com significados distintos (ex: eminente/iminente, comprimento/cumprimento). Campo semântico e família semântica.', ['Diferencie polissemia e homonímia com exemplos práticos.', 'Corrija o uso dos parônimos neste texto.']),
  createLesson('g2-por-b1-l8', 'L8: Pragmática e Análise do Discurso', 'portugues', 'Pragmática: o uso da linguagem em contexto. Atos de fala: assertivos, diretivos, compromissivos, expressivos, declarativos. Implicatura conversacional (Grice): o que se comunica além do que se diz. Máximas de Grice: quantidade, qualidade, relação, modo. Análise do discurso: como o discurso reproduz e questiona relações de poder. Discurso midiático: como a imprensa constrói realidade. Propaganda e ideologia. Análise crítica do discurso publicitário e político.', ['Analise este discurso político: que implicaturas e estratégias persuasivas usa?', 'Como a mídia constrói uma imagem de determinado grupo social neste texto?']),
  createLesson('g2-por-b1-l9', 'L9: Texto Científico e Acadêmico', 'portugues', 'Características do texto científico: objetividade, impessoalidade, precisão, evidência, citação de fontes. Estrutura do artigo científico: resumo (abstract), introdução, metodologia, resultados, discussão, conclusão, referências. Resumo acadêmico: como escrever. Resenha: leitura crítica de uma obra (resumo + análise + posição). Fichamento: sistematização de leitura. Ler textos científicos em português: habilidade necessária para o ensino superior e para o ENEM (que inclui textos de divulgação científica).', ['Leia este texto de divulgação científica e responda: qual é a tese e os argumentos?', 'Escreva um resumo acadêmico de 150 palavras deste texto científico.']),
  createLesson('g2-por-b1-l10', 'L10: Concordância — Casos Especiais', 'portugues', 'Concordância verbal — casos especiais avançados: sujeito coletivo (partitivo), "um dos que" (verbo no plural), "mais de um" (singular ou plural?), sujeito posposto com verbos existenciais/impessoais (haver, fazer = impessoais), pronomes indefinidos como sujeito. Concordância nominal — casos especiais: predicativo do sujeito com sujeito múltiplo, locuções adjetivas, adjetivos com nomes de partes do corpo, "é proibido/é necessário/é preciso". ENEM cobra estes casos com frequência.', ['Justifique a concordância em cada uma destas frases de alta complexidade.', 'Corrija os erros de concordância neste texto formal.']),
  createLesson('g2-por-b1-l11', 'L11: Regência e Crase — Casos Especiais', 'portugues', 'Regência verbal avançada: verbos com dupla regência e mudança de sentido (aspirar, implicar, proceder, satisfazer, simpatizar). Regência nominal: adjetivos que exigem preposição (ansioso por, compatível com, leal a). Crase — casos especiais: crase antes de pronome possessivo feminino (à minha...), crase em locuções adverbiais femininas, crase antes de numerais, crase com "a" artigo + "a" preposição. Quando NÃO há crase: antes de masculino, verbo, pronome pessoal. Exercícios de nível ENEM e vestibular.', ['Justifique o uso ou não uso da crase em cada um destes casos.', 'Corrija os erros de regência verbal e nominal neste trecho.']),
  createLesson('g2-por-b1-l12', 'L12: Colocação Pronominal — Casos Especiais', 'portugues', 'Colocação pronominal: próclise (pronome antes do verbo), ênclise (pronome depois do verbo), mesóclise (pronome no meio do verbo — futuro do presente/do pretérito). Regras: próclise obrigatória com palavras atrativas (negação, conjunções subordinativas, pronomes relativos, advérbios). Ênclise: início de frase, após pausa, imperativo afirmativo. Mesóclise: rara, formal. Pronome com locuções verbais: posição variada. Norma culta vs. uso coloquial brasileiro. O ENEM cobra em contexto.', ['Justifique a colocação pronominal em cada exemplo deste texto literário.', 'Reescreva estas frases adequando a colocação pronominal à norma culta.']),
  createLesson('g2-por-b1-l13', 'L13: Aspectos Formais do Texto Poético', 'portugues', 'Métricas: sílabas poéticas (diferente de sílabas gramaticais). Escansão: divisão em sílabas poéticas (sinalefa, ditongação, sinérese, diérese). Versos: tipos por sílabas (octossílabo, decassílabo, alexandrino). Rima: esquemas (ABAB, ABBA, AABB). Ritmo: acentuação, pausa (cesura), pé métrico. Estrofe: dístico, terceto, quarteto, quintilha, sextilha, sétima, oitava, décima. Soneto: estrutura fixa (2 quartetos + 2 tercetos). Verso livre e verso branco. Análise de poema canônico.', ['Faça a escansão deste poema e identifique o esquema métrico e de rimas.', 'Analise a relação entre forma (verso, estrofe, rima) e conteúdo neste soneto.']),
  createLesson('g2-por-b1-l14', 'L14: Crônica — Gênero Híbrido', 'portugues', 'A crônica: entre o jornalismo e a literatura. Características: texto curto, baseado no cotidiano, tom coloquial ou literário, atualidade, humor ou lirismo, visão crítica do dia a dia. Cronistas brasileiros: Rubem Braga (lirismo), Drummond, Paulo Mendes Campos, Luís Fernando Veríssimo (humor), Fernando Sabino, João do Rio. Crônica no ENEM: frequente. Relação crônica × notícia × conto. Como escrever uma crônica. Prática de leitura e escrita.', ['O que transforma um fato cotidiano em crônica literária? Analise este exemplo.', 'Escreva uma crônica curta sobre algo do cotidiano escolar ou da cidade de Palmas.']),
  createLesson('g2-por-b1-l15', 'L15: Produção Textual — Dissertação com Argumentos Sólidos', 'portugues', 'Elevando a qualidade argumentativa. Tipos de argumento em profundidade: argumento de autoridade (citação pertinente e bem integrada), argumento histórico (fatos históricos como evidência), argumento por analogia (comparação com situação similar), argumento por exemplificação (caso concreto e específico). Evitar: argumentos circulares, falácias lógicas (ad hominem, homem de palha, generalização apressada). Construir um "repertório cultural" para a redação: leituras, notícias, história.', ['Reescreva este parágrafo fraco usando um argumento de autoridade bem integrado.', 'Identifique a falácia lógica em cada um destes "argumentos" de redações reais.']),
  createLesson('g2-por-b1-l16', 'L16: Leitura e Interpretação — Textos Complexos', 'portugues', 'Lendo textos de alta complexidade: textos filosóficos, sociológicos, linguísticos. Identificar: tese, premissas, conclusão. Relações lógicas: causa, consequência, analogia, oposição. Inferência em textos complexos: o que o autor pressupõe? O que implica sem dizer? Vocabulário especializado: deduzir do contexto. ENEM inclui textos de Filosofia, Sociologia, História nas provas de Linguagens. Prática com textos de Foucault, Bourdieu, Hobsbawm (trechos adaptados).', ['Identifique a tese e 3 premissas neste texto filosófico.', 'O que o autor pressupõe sem afirmar explicitamente neste trecho?']),
  createLesson('g2-por-b1-l17', 'L17: Simulado — ENEM Linguagens', 'portugues', 'Simulado do estilo ENEM para Linguagens e Códigos. 15 questões de Língua Portuguesa cobrindo: interpretação de textos variados, literatura (escola literária, análise de fragmento), gramática em contexto, figuras de linguagem, variação linguística, gêneros textuais. Tempo: 45 minutos. Correção comentada detalhada. Análise de padrões: que habilidades o ENEM mais testa em LP? Como pontuar mais alto.', ['Resolva o simulado em condições de prova (45 minutos, sem consulta).', 'Após a correção: liste os 3 tipos de questão que você mais errou e estude-os.']),
  createLesson('g2-por-b1-l18', 'L18: Revisão do Bimestre 1', 'portugues', 'Revisão do 1º Bimestre de 2ª série: texto e discurso, Realismo português (Eça), Simbolismo, Fernando Pessoa, vanguardas europeias, morfossintaxe avançada, semântica, pragmática, texto científico/acadêmico, concordância/regência/crase/colocação avançadas, poesia formal, crônica, argumentação avançada, leitura de textos complexos. Simulado de revisão. Planejamento para o 2º Bimestre.', ['Resolva este simulado de revisão abrangente do 1º Bimestre.', 'Quais tópicos foram mais difíceis? Monte um plano de revisão específico.']),
];

export const porLessonsB2: Lesson[] = [
  createLesson('g2-por-b2-l1', 'L1: Modernismo Português — Geração de Orpheu', 'portugues', 'Modernismo português (a partir de 1915): Revista Orpheu. Fernando Pessoa e seus heterônimos (aprofundamento). Mário de Sá-Carneiro: "Lúcio Ralo", "Dispersão". Almada Negreiros. Revistas: Orpheu (1915), Presença (segunda geração — Eugénio de Andrade, José Régio). Diferenças entre o Modernismo português e o brasileiro: contexto histórico, influências, temas. Portugal do Estado Novo (Salazar) e sua influência na literatura. Neo-Realismo português.', ['Compare o Modernismo português e o brasileiro: que contextos históricos os diferenciam?', 'Analise a fragmentação do eu em um poema de Fernando Pessoa ou Mário de Sá-Carneiro.']),
  createLesson('g2-por-b2-l2', 'L2: Literatura Africana de Língua Portuguesa', 'portugues', 'Literaturas africanas de língua portuguesa (PALOP): Angola, Moçambique, Cabo Verde, São Tomé e Príncipe, Guiné-Bissau. Contexto: colonização, resistência, independência (anos 1970). Négritude: movimento literário de afirmação da identidade negra. Angola: José Saramago, Luandino Vieira, Agualusa. Moçambique: Mia Couto ("Terra Sonâmbula", "A Chuva Pasmada"). Cabo Verde: Claridade. A língua portuguesa como herança colonial e como instrumento de libertação.', ['O que significa a língua portuguesa para os escritores africanos que a usam para resistir?', 'Analise um texto de Mia Couto: que características da sua escrita o tornam único?']),
  createLesson('g2-por-b2-l3', 'L3: Concretismo e Poesia Visual', 'portugues', 'Concretismo brasileiro (1950s-60s): "Plano-Piloto para Poesia Concreta" (Noigandres: Augusto de Campos, Haroldo de Campos, Décio Pignatari). A palavra como objeto visual e sonoro. Forma = conteúdo. Influências: Mallarmé, e.e. cummings, Pound. "Tensão, palavra, gestalt". "Beba Coca Cola" (Décio Pignatari) — crítica ao consumismo. Poesia visual contemporânea. Arte concreta, design, tipografia. O ENEM usa poemas concretos nas provas.', ['Analise um poema concreto: como a disposição visual cria significado?', 'Crie um pequeno poema concreto sobre um tema de sua escolha.']),
  createLesson('g2-por-b2-l4', 'L4: Literatura e Ditadura Militar (1964-1985)', 'portugues', 'O período da ditadura militar no Brasil e seus reflexos na literatura. Censura e resistência. Tropicalismo: Caetano Veloso, Gilberto Gil — mistura de MPB, rock, vanguarda, crítica social. Teatro: Augusto Boal — "Teatro do Oprimido". Cinema Novo: Glauber Rocha. Literatura de resistência: Ferreira Gullar ("Poema Sujo"), Chico Buarque (letras como literatura). Tropicalismo e contracultura. Memória e esquecimento: literatura e ditadura hoje.', ['Como artistas resistiram à censura durante a ditadura militar? Dê exemplos literários/musicais.', 'Analise a letra de uma música de Chico Buarque do período ditatorial: que crítica veicula?']),
  createLesson('g2-por-b2-l5', 'L5: Língua e Identidade Nacional', 'portugues', 'A língua portuguesa e a identidade brasileira: como a língua nos constitui como nação. Diferenças entre Português Brasileiro e Português Europeu: vocabulário, pronúncia, gramática. Por que o português brasileiro é diferente? Influências indígenas, africanas, imigrantes. A questão da língua na Independência e no Romantismo. Língua e política: debates sobre "certo" e "errado". Língua e poder: quem decide o que é "norma culta"? Gramática normativa vs. descritiva.', ['Por que o Português Brasileiro evoluiu de forma diferente do Português Europeu?', 'Que palavras do cotidiano brasileiro têm origem indígena ou africana? Pesquise 10.']),
  createLesson('g2-por-b2-l6', 'L6: Texto Argumentativo — Estratégias Retóricas', 'portugues', 'Retórica (Aristóteles): ethos (credibilidade do autor), pathos (apelo à emoção), logos (apelo à razão). Estratégias argumentativas no texto dissertativo: pergunta retórica, concessão seguida de refutação, antítese argumentativa, analogia, exemplum, argumento de autoridade. Estruturas de argumentação: toulmin (dado, garantia, apoio, qualificador, refutação, conclusão). Análise de editoriais, artigos de opinião, manifestos. Construindo argumentos irrefutáveis.', ['Analise as estratégias retóricas (ethos, pathos, logos) neste editorial.', 'Construa um argumento usando a estrutura toulmin sobre um tema social.']),
  createLesson('g2-por-b2-l7', 'L7: Leitura de Imagens e Textos Multimodais', 'portugues', 'Letramento visual: ler imagens como textos. Elementos visuais: cor, luz, perspectiva, composição, enquadramento, símbolos. Fotografia jornalística: o que uma foto diz que o texto não diz? Charge e caricatura: exagero, símbolo, humor e crítica. Infográfico: dado + visual + texto. Tirinha: narrativa em quadrinhos, linguagem do humor. Propaganda política e publicitária: análise crítica. O ENEM usa muito o texto multimodal — saber ler imagem é saber ler a prova.', ['Analise esta charge: quem são os personagens? Que evento histórico ou social é criticado?', 'Compare a fotografia e a notícia escrita sobre o mesmo evento: que informações cada uma prioriza?']),
  createLesson('g2-por-b2-l8', 'L8: Produção de Redação — Temas Polêmicos', 'portugues', 'Como abordar temas polêmicos na redação do ENEM sem ferir os direitos humanos. Temas como: aborto, legalização de drogas, pena de morte, cotas raciais, eutanásia. Princípio dos direitos humanos (Competência 5): a proposta de intervenção não pode defender violência, discriminação, ou ações ilegais. Como argumentar sobre temas polêmicos sem "fuga ao tema" e sem "nota 0". Análise de redações sobre temas polêmicos: o que funciona e o que reprova.', ['Como você abordaria o tema da legalização do aborto em uma redação do ENEM respeitando os direitos humanos?', 'Reescreva esta proposta de intervenção que viola os direitos humanos.']),
  createLesson('g2-por-b2-l9', 'L9: Oração — Revisão e Aprofundamento Sintático', 'portugues', 'Revisão do período composto. Subordinação substantiva, adjetiva, adverbial (revisão das 9 espécies). Coordenação (5 espécies). Casos de dupla leitura: oração que pode ser interpretada como coordenada ou subordinada. Redução de orações: gerúndio, particípio, infinitivo — qual o valor semântico de cada redução? Análise sintática de textos literários e jornalísticos complexos. Uso estratégico de subordinadas na redação para criar argumentos sofisticados.', ['Analise sintaticamente este parágrafo complexo de um texto jornalístico.', 'Reescreva este texto usando mais orações subordinadas para sofisticar a argumentação.']),
  createLesson('g2-por-b2-l10', 'L10: Estilística — Recursos Expressivos na Literatura', 'portugues', 'Estilística: estudo do estilo — como cada autor usa a língua de forma única. Análise estilística: vocabulário escolhido, estrutura sintática, figuras de linguagem predominantes, ritmo, tom. O estilo como identidade do autor. Comparação de estilos: Machado de Assis (ironia fina), Guimarães Rosa (neologismo, síntese do sertão), Clarice Lispector (fluxo de consciência, introspectiva), Drummond (coloquial + filosófico). O ENEM pede: "O estilo usado no texto é...".', ['Identifique as marcas de estilo do autor neste fragmento desconhecido.', 'Compare o estilo de dois autores modernistas: que recursos cada um privilegia?']),
  createLesson('g2-por-b2-l11', 'L11: Leitura de Romances — Técnicas Narrativas Avançadas', 'portugues', 'Técnicas narrativas do romance moderno e contemporâneo. Fluxo de consciência (stream of consciousness): Clarice Lispector, Virgínia Woolf. Monólogo interior. Narrador não confiável: Machado de Assis, José Saramago. Metalinguagem: o texto que fala de si mesmo. Paródia e pastiche. Fragmentação narrativa. Narrativa em segunda pessoa (rara mas existe). Tempo não linear: analepse (flashback), prolepse (antecipação). Análise de fragmentos de romances modernos.', ['Identifique as técnicas narrativas usadas neste fragmento de Clarice Lispector.', 'O narrador deste conto é confiável? Que evidências no texto sustentam sua resposta?']),
  createLesson('g2-por-b2-l12', 'L12: Literatura e Cinema', 'portugues', 'Adaptações literárias para o cinema: fidelidade vs. interpretação. Como o cinema recria a literatura: escolhas do diretor, linguagem cinematográfica (plano, enquadramento, trilha, edição) vs. linguagem literária. Exemplos brasileiros: "Grande Sertão: Veredas" (adaptações), "Central do Brasil" (baseado em realidade brasileira), "Cidade de Deus" (Paulo Lins → Fernando Meirelles). Intertextualidade entre literatura e cinema. Cinema como literatura visual. Análise de uma cena de filme adaptado de romance.', ['Compare uma cena do filme com o trecho correspondente do livro: o que mudou? Por quê?', 'Que recursos o cinema usa que a literatura não pode? E vice-versa?']),
  createLesson('g2-por-b2-l13', 'L13: Gêneros Orais e Fala Pública', 'portugues', 'Oralidade e letramento: diferenças entre fala e escrita. Gêneros orais: debate, seminário, discurso, entrevista, podcast, videoaula. Características da fala: planejamento online, hesitação, repetição, marcadores conversacionais. Gêneros orais formais: como planejar, estruturar e apresentar. Debate regrado: argumentação, réplica, tréplica, conclusão. Comunicação oral como competência para cidadania e carreira. Gravação e autoavaliação de fala.', ['Prepare e apresente um seminário de 5 minutos sobre um tema literário estudado.', 'Realize um debate em sala sobre: "O preconceito linguístico prejudica a educação brasileira".']),
  createLesson('g2-por-b2-l14', 'L14: Ensaio e Artigo de Opinião', 'portugues', 'Ensaio: texto argumentativo de caráter pessoal e reflexivo (Montaigne como pai do ensaio). Características: subjetividade controlada, reflexão profunda, exemplificação literária/histórica/filosófica. Artigo de opinião: mais formal que o ensaio, com assinatura, publicado em jornal/revista. Diferença de artigo de opinião e editorial. Como citar fontes em texto de opinião. Produção de um artigo de opinião para um tema atual. Gênero frequente no ENEM como texto de suporte.', ['Escreva um artigo de opinião sobre: "O papel da leitura na formação cidadã".', 'Qual é a diferença entre um editorial e um artigo de opinião? Analise estes exemplos.']),
  createLesson('g2-por-b2-l15', 'L15: Heteroglossia e Dialogismo — Bakhtin', 'portugues', 'Mikhail Bakhtin: linguagem como fenômeno social e dialógico. Dialogismo: todo enunciado dialoga com outros enunciados (passados e futuros). Polifonia: múltiplas vozes em um texto. Heteroglossia: diversidade de linguagens sociais dentro de uma língua. Romance polifônico vs. monológico. Carnavalização: subversão da ordem pelo riso (Rabelais). Aplicando Bakhtin: analisar como textos dialogam com outros textos e com a sociedade. Teorias bakhtinianas presentes implicitamente no ENEM.', ['Como o conceito de dialogismo de Bakhtin se aplica a este romance ou conto?', 'Identifique as vozes sociais diferentes presentes neste texto jornalístico.']),
  createLesson('g2-por-b2-l16', 'L16: Produção Textual — Carta Aberta e Manifesto', 'portugues', 'Gêneros de intervenção social: carta aberta (endereçada a um grupo ou instituição, publicada), manifesto (declaração de posição coletiva). Características: enunciador coletivo ou que fala por um grupo, interpelação direta ao destinatário, tom assertivo, propósito de mudança. Exemplos históricos: Manifesto Comunista, Manifesto Antropófago, Carta de Pero Vaz de Caminha (como carta). Produção: carta aberta sobre um problema da comunidade escolar de Palmas/Tocantins.', ['Escreva uma carta aberta ao poder público sobre um problema da sua comunidade em Tocantins.', 'Analise o Manifesto Antropófago: que propósito ele cumpria? Que recursos usa?']),
  createLesson('g2-por-b2-l17', 'L17: Simulado — ENEM Linguagens (2ª Série)', 'portugues', 'Simulado de Linguagens para 2ª série: questões de nível mais elevado que as de 1ª série. Textos mais complexos, literatura portuguesa e africana incluída, gramática avançada. 15 questões + planejamento de redação sobre tema proposto. Identificação de padrões do ENEM para a 2ª série: o que o exame espera de um candidato neste nível. Análise de desempenho e retorno individualizado.', ['Resolva o simulado em condições de prova.', 'Analise: em que habilidade você avançou em relação à 1ª série? O que ainda falta?']),
  createLesson('g2-por-b2-l18', 'L18: Revisão do Bimestre 2', 'portugues', 'Revisão do 2º Bimestre: Modernismo português, literatura africana, Concretismo, literatura e ditadura, língua e identidade, retórica, texto multimodal, redação com temas polêmicos, sintaxe avançada, estilística, técnicas narrativas avançadas, literatura e cinema, gêneros orais, ensaio/artigo de opinião, Bakhtin, carta aberta/manifesto. Simulado de revisão do bimestre. Balanço do primeiro semestre.', ['Resolva o simulado de revisão do 2º Bimestre.', 'Quais foram as 3 descobertas mais importantes que você fez na Língua Portuguesa este semestre?']),
];

export const porLessonsB3: Lesson[] = [
  createLesson('g2-por-b3-l1', 'L1: Literatura Comparada', 'portugues', 'Literatura comparada: estudo de relações entre literaturas de diferentes línguas e culturas. Influências, diálogos, traduções, adaptações. Brasil e Portugal: herança literária e diferenciação. América Latina em português e espanhol: realismo mágico (Márquez) e literatura brasileira. Universalismo e particularismo na literatura. Comparação: Machado de Assis e Dostoiévski (psicologia); Guimarães Rosa e Faulkner (região e universalidade); Clarice e Woolf (fluxo de consciência).', ['Compare dois autores de literaturas diferentes que abordam o mesmo tema. Que diferenças e semelhanças encontra?', 'O que é o realismo mágico? Como ele difere do realismo literário?']),
  createLesson('g2-por-b3-l2', 'L2: Oralidade na Literatura', 'portugues', 'A voz oral na literatura escrita: como a oralidade é incorporada. Literatura popular: cordel, repente, embolada, adivinhas, provérbios. Cordel: origem ibérica, nordeste brasileiro. Poetas populares: Leandro Gomes de Barros, João Pessoa, Patativa do Assaré. A voz nordestina em Guimarães Rosa e Graciliano. Slam poetry: poesia falada contemporânea, performática, engajada. A literatura das margens: vozes silenciadas que chegam à escrita. Sarau: prática coletiva de literatura.', ['Leia um cordel e analise: estrutura, linguagem, temática, função social.', 'Assista a uma apresentação de slam poetry e analise: como a voz e o corpo contribuem para o poema?']),
  createLesson('g2-por-b3-l3', 'L3: Análise Textual Integrada', 'portugues', 'Integração de todas as ferramentas de análise textual: o texto como unidade de significado onde forma e conteúdo são inseparáveis. Analisar simultaneamente: gênero, tipo, função, contexto de produção, recursos linguísticos, figuras de linguagem, estrutura sintática, posicionamento ideológico, intertextualidade, efeitos de sentido. Análise completa de um texto longo (literário ou jornalístico). Preparação para questões do ENEM que pedem análise integrada.', ['Faça uma análise textual integrada completa deste texto (literário ou jornalístico).', 'Como os recursos linguísticos escolhidos pelo autor reforçam ou contradizem seu conteúdo?']),
  createLesson('g2-por-b3-l4', 'L4: Gêneros Digitais e Linguagem na Internet', 'portugues', 'A língua na internet: novos gêneros, novas normas. Blog, vlog, podcast, story, post, tweet, thread, meme, e-mail, chat. Oralidade escrita: como escrevemos parecendo falar na internet. Emoji como signo: comunicação multimodal digital. Netiqueta: comportamento adequado online. Fake news: como identificar, linguagem da desinformação. Hiperestimulação e atenção: como a internet transforma a leitura. Cidadania digital: responsabilidade no uso da língua online.', ['Analise um meme viral: que recursos linguísticos usa para criar humor ou crítica?', 'Como a linguagem de um tweet difere de um e-mail formal? Analise exemplos reais.']),
  createLesson('g2-por-b3-l5', 'L5: Escrita Criativa — Conto e Crônica', 'portugues', 'Oficina de escrita criativa. Conto: narrador, personagens, conflito, clímax, desfecho — em poucas páginas. Técnicas: começar in media res (no meio da ação), criar personagens com profundidade em poucas linhas, desfecho inesperado. Crônica: transformar o ordinário em extraordinário. Processo de escrita: brainstorming, rascunho, revisão, edição. Oficina: escrever, ler em voz alta, receber feedback, reescrever. A escrita como prática — não como dom inato.', ['Escreva um conto de até 500 palavras com início, meio e fim bem definidos.', 'Transforme este fato cotidiano em uma crônica literária (200-300 palavras).']),
  createLesson('g2-por-b3-l6', 'L6: Redação ENEM — Oficina de Competências', 'portugues', 'Oficina focada em cada competência do ENEM. Competência 1 (norma culta): exercícios de ortografia, concordância, pontuação. Competência 2 (tema): como garantir a análise do tema sem desvio. Competência 3 (argumentação): construir uma progressão lógica de argumentos. Competência 4 (coesão): exercícios com conectivos, pronomes de retomada, progressão temática. Competência 5 (intervenção): modelo de proposta com os 5 elementos. Análise de redações reais com notas variadas.', ['Analise esta redação (com nota revelada depois) competência por competência.', 'Reescreva este parágrafo melhorando especificamente a coesão (Competência 4).']),
  createLesson('g2-por-b3-l7', 'L7: Linguagem dos Quadrinhos', 'portugues', 'A linguagem dos quadrinhos (HQ): arte sequencial. Elementos: requadro (panel), sarjeta (gutter), balão (fala, pensamento, off-screen), legenda, onomatopeia, expressão facial, linguagem corporal, perspectiva. Tirinha vs. HQ vs. mangá vs. graphic novel. Quadrinhos brasileiros: Maurício de Sousa (Turma da Mônica), Laerte, Angeli, Gonsalves Jr. Quadrinhos como literatura: Art Spiegelman ("Maus"), Persépolis (Marjane Satrapi). O ENEM usa tirinhas — saber lê-las é fundamental.', ['Analise esta tirinha: como os elementos visuais e verbais criam o humor ou a crítica?', 'Crie uma tirinha de 4 quadrinhos sobre um tema de sua escolha.']),
  createLesson('g2-por-b3-l8', 'L8: Produção de Redação — Revisão e Reescrita', 'portugues', 'Revisão e reescrita como partes do processo de escrita — não como correção de erros, mas como aprimoramento. Estratégias de autorrevisar: ler em voz alta, afastar-se do texto e reler depois, usar checklist. Revisão por pares: dar e receber feedback construtivo. Reescrever parágrafos: começando o parágrafo de outro jeito, trocando os argumentos de ordem, melhorando as transições. Portfólio de redações: ver o crescimento ao longo do ano.', ['Pegue sua redação do bimestre anterior e reescreva-a melhorando todos os aspectos.', 'Faça a revisão por pares de uma redação usando a grade do ENEM.']),
  createLesson('g2-por-b3-l9', 'L9: Semântica Avançada — Ambiguidade e Polissemia', 'portugues', 'Ambiguidade: quando uma expressão admite mais de uma interpretação (pode ser intencional na literatura, indesejada na comunicação funcional). Polissemia avançada: sentidos múltiplos de palavras abstratas. Isotopia: conjunto de traços semânticos que dão coerência temática ao texto. Pressuposição: informação assumida como verdadeira antes de ser afirmada. Subentendido: informação que pode ser inferida mas não está pressuposta. Implicatura: o que se comunica além do literal. Análise semântica de textos literários e publicitários.', ['Identifique as ambiguidades neste texto e explique seus efeitos.', 'Analise as pressuposições e subentendidos neste anúncio publicitário.']),
  createLesson('g2-por-b3-l10', 'L10: Análise de Letras de Música como Texto', 'portugues', 'Letra de música como texto literário: análise completa. MPB como literatura: Chico Buarque, Caetano Veloso, Gilberto Gil, Milton Nascimento, Djavan, Renato Russo (Legião Urbana). Funk, rap, sertanejo universitário: analisar a linguagem. Hip-hop e rap: poesia urbana periférica — Criolo, Emicida, Racionais MC\'s. Figuras de linguagem na música, ambiguidade, duplo sentido. A letra de música como documento histórico e social. O ENEM inclui letras de músicas frequentemente.', ['Analise a letra desta música: figuras de linguagem, tema, contexto histórico, crítica social.', 'Compare uma música da ditadura e uma atual sobre o mesmo tema. O que mudou?']),
  createLesson('g2-por-b3-l11', 'L11: Norma Culta e Variação — Debate Final', 'portugues', 'Debate aprofundado: o que é a "norma culta" e quem a define. Gramáticas descritivas vs. normativas. O mito da "língua certa": Marcos Bagno e a crítica ao preconceito linguístico. Gramática internalizada vs. gramática ensinada. O papel da escola na transmissão da norma culta. Questão social: quem tem acesso à norma culta? Bilinguismo e diglossia no Brasil. O ENEM como exame que testa a norma culta mas também a capacidade de reconhecer variação. Posição crítica.', ['Você acha que a escola deveria ensinar "norma culta" ou "variação linguística"? Argumente.', 'Leia este texto de Marcos Bagno sobre preconceito linguístico e resuma seus argumentos principais.']),
  createLesson('g2-por-b3-l12', 'L12: Simulado ENEM — Linguagens e Língua Portuguesa', 'portugues', 'Simulado completo e avançado de Linguagens para 2ª série. Questões com maior complexidade textual e literária. 15 questões de LP + planejamento detalhado de redação. Foco em inferência, análise estilística, intertextualidade — habilidades de nível mais avançado. Tempo: 50 minutos. Análise comparativa de desempenho com simulados anteriores. Devolutiva: apontamento de lacunas específicas para o último bimestre.', ['Resolva o simulado avançado em condições de prova.', 'Identifique sua lacuna mais importante e crie um plano de estudo para o 4º Bimestre.']),
  createLesson('g2-por-b3-l13', 'L13: Teoria Literária — Breve Introdução', 'portugues', 'Introdução à teoria literária: como a crítica analisa a literatura. Formalismo russo: o que torna um texto literário — "literariedade". Estruturalismo: narratologia (Greimas, Propp — funções do conto). New Criticism: close reading, texto como objeto autônomo. Pós-estruturalismo: Derrida (desconstrução). Crítica feminista: representação da mulher. Crítica pós-colonial: quem narra? Do centro ou da margem? Estas teorias aparecem implicitamente nas questões mais difíceis do ENEM.', ['Aplique a análise feminista a este conto: como a mulher é representada?', 'Usando a perspectiva pós-colonial, analise como o nativo brasileiro é representado neste texto do período colonial.']),
  createLesson('g2-por-b3-l14', 'L14: Projeto de Leitura — Romance Brasileiro', 'portugues', 'Leitura orientada de um romance brasileiro completo (indicação do professor). Discussão em grupo: enredo, personagens, temas, estilo. Registro de leitura: diário de leitura — reações, dúvidas, descobertas. Trabalho final: análise literária do romance (oralmente ou por escrito). Objetivo: vivenciar a leitura literária como prática sustentada, não como tarefa. Conectar o romance com o contexto histórico e social de sua produção.', ['Escreva um capítulo do diário de leitura do romance (reações, análise de personagem, tema).', 'Apresente oralmente (3-5 minutos) sua análise de um aspecto do romance que mais chamou sua atenção.']),
  createLesson('g2-por-b3-l15', 'L15: Escrita Criativa — Poesia', 'portugues', 'Oficina de escrita poética. Poesia de forma fixa: soneto, haiku (brasileira: 5-7-5 em sílabas), villanelle. Poesia livre: sem métrica ou rima forçada, mas com cuidado no ritmo e imagens. Imagem poética: o concreto evocando o abstrato. Metáfora central: a pedra angular do poema. Poesia como concentração de linguagem. Ler um poema lentamente. Escrever, reler, reescrever. Compartilhar em rodada poética (sarau). Poesia como autoconhecimento.', ['Escreva um poema em forma de soneto sobre um tema de sua escolha.', 'Escreva um poema livre usando pelo menos 3 figuras de linguagem estudadas no ano.']),
  createLesson('g2-por-b3-l16', 'L16: Patrimônio Cultural e Língua Portuguesa', 'portugues', 'Língua portuguesa como patrimônio imaterial da humanidade. CPLP (Comunidade dos Países de Língua Portuguesa): Brasil, Portugal, Angola, Moçambique, Cabo Verde, São Tomé e Príncipe, Guiné-Bissau, Timor-Leste, Macau. 260+ milhões de falantes. O Português no mundo: segunda língua mais falada na América do Sul, na África subsaariana, etc. Acordo Ortográfico de 1990 (e 2009): aproximação e polêmica. Orgulho da língua e responsabilidade como usuário.', ['Pesquise um aspecto da cultura de um país lusófono. Apresente para a turma.', 'Você acha que o Acordo Ortográfico foi benéfico? Argumente com base em fatos.']),
  createLesson('g2-por-b3-l17', 'L17: Redação — Tema Ambiental', 'portugues', 'Prática de redação com tema ambiental (recorrente no ENEM). Tema sugerido: "Estratégias para a preservação do Cerrado, bioma do Tocantins". Construindo argumentos específicos sobre o Cerrado: biodiversidade, recursos hídricos, agronegócio sustentável, povos do cerrado, queimadas. Proposta de intervenção com agentes específicos: governo do Tocantins, agricultores, escola, mídia. Usando dados reais e exemplos locais. O ENEM valoriza especificidade na proposta.', ['Escreva uma redação completa sobre a preservação do Cerrado, usando dados e exemplos do Tocantins.', 'Avalie: sua proposta de intervenção é específica o suficiente para receber nota máxima na Competência 5?']),
  createLesson('g2-por-b3-l18', 'L18: Revisão do Bimestre 3', 'portugues', 'Revisão do 3º Bimestre: literatura comparada, oralidade na literatura, análise textual integrada, gêneros digitais, escrita criativa (conto/crônica/poesia), redação (competências, revisão, temas polêmicos), quadrinhos, semântica avançada, letras de música, norma culta e variação, teoria literária, projeto de leitura, patrimônio linguístico. Simulado de revisão. Planejamento para o último bimestre.', ['Resolva o simulado de revisão do 3º Bimestre.', 'Liste os conteúdos que você mais precisa revisar antes das avaliações finais.']),
];

export const porLessonsB4: Lesson[] = [
  createLesson('g2-por-b4-l1', 'L1: ENEM — Revisão de Literatura', 'portugues', 'Revisão estratégica de literatura para o ENEM: todas as escolas literárias de forma contextualizada. O ENEM não pede decoreba — pede leitura e interpretação de fragmentos. Estratégia: identificar características da escola literária no próprio texto (não pela memorização isolada). Escolas mais cobradas: Modernismo, Romantismo, Realismo, Barroco. Autores mais frequentes: Drummond, Machado, Guimarães Rosa, Clarice, Fernando Pessoa. Prática com questões reais.', ['Resolva estas 10 questões de literatura do ENEM (2018-2023).', 'Para cada questão, explique: como o texto em si revela a escola literária?']),
  createLesson('g2-por-b4-l2', 'L2: ENEM — Revisão de Gramática em Contexto', 'portugues', 'Gramática no ENEM: sempre em contexto textual. Revisão dos pontos mais cobrados: concordância (casos especiais), regência verbal e nominal, crase (todos os casos), colocação pronominal, pontuação (vírgula), ortografia pós-reforma. Exercícios com questões reais do ENEM de gramática. Estratégia: focar no "o que muda o sentido" — não na nomenclatura. Análise de como erros gramaticais aparecem nas opções erradas do ENEM.', ['Resolva estas 10 questões de gramática em contexto do ENEM.', 'Em quais pontos gramaticais você ainda tem mais dúvida? Faça exercícios específicos.']),
  createLesson('g2-por-b4-l3', 'L3: ENEM — Interpretação e Figuras de Linguagem', 'portugues', 'Revisão de interpretação textual e figuras de linguagem para o ENEM. Perguntas frequentes: "O recurso expressivo neste verso é...", "O uso de X cria o efeito de...", "A linguagem deste texto é predominantemente...". Figuras mais cobradas: metáfora, metonímia, hipérbole, ironia, antítese, eufemismo, personificação. Como a figura cria efeito de sentido — não apenas nomenclatura. Prática com 15 questões reais do ENEM.', ['Resolva estas 15 questões do ENEM sobre interpretação e figuras de linguagem.', 'Para cada figura identificada, explique o efeito no contexto — não apenas o nome.']),
  createLesson('g2-por-b4-l4', 'L4: Redação ENEM — Simulado Final I', 'portugues', 'Simulado de redação: tema proposto com 4-5 textos motivadores (como no ENEM real). 60 minutos para escrever. Depois: autocorreção usando a grade de competências (1-5). Correção pelo professor com feedback detalhado por competência. Identificação de progressão desde a primeira redação do ano. Pontos críticos de nota: fuga ao tema, violação de direitos humanos, incoerência na proposta. A redação é 20% da nota de Linguagens — estrategicamente importantíssima.', ['Escreva uma redação completa em 60 minutos sobre o tema proposto.', 'Autoavalie sua redação competência por competência e estime sua nota.']),
  createLesson('g2-por-b4-l5', 'L5: Redação ENEM — Simulado Final II', 'portugues', 'Segundo simulado de redação: novo tema, novas estratégias. Foco neste simulado: aplicar o feedback do simulado anterior. Rever: proposta de intervenção mais detalhada, coesão mais sofisticada, argumento mais sólido. Estratégia de tempo: 10-10-40-10 (leitura motivadores, planejamento, escrita, revisão). Troca de redações entre colegas para correção cruzada usando a grade. Discussão coletiva: o que tornou as melhores redações realmente boas?', ['Escreva a redação simulada 2 aplicando o feedback recebido no simulado 1.', 'Corrija a redação do colega e dê feedback específico usando a grade de competências.']),
  createLesson('g2-por-b4-l6', 'L6: Leitura Extensiva — Clássicos da Literatura', 'portugues', 'Importância da leitura extensiva para o desenvolvimento da competência leitora e escritora. Leitura de trechos de clássicos da literatura brasileira: "Dom Casmurro", "Vidas Secas", "Grande Sertão: Veredas", "A Hora da Estrela". Discussão: o que os torna clássicos? Por que ainda são relevantes? Como a literatura clássica alimenta a redação: repertório cultural, perspectiva histórica, sofisticação de linguagem. Leitura como prazer e como investimento intelectual.', ['Leia este trecho de um clássico e apresente para a turma: o que o torna especial?', 'Como o repertório cultural adquirido pela leitura pode enriquecer uma redação do ENEM?']),
  createLesson('g2-por-b4-l7', 'L7: Projeto Final — Antologia Literária da Turma', 'portugues', 'Projeto coletivo: produzir uma antologia com as melhores produções literárias e argumentativas da turma durante o ano. Cada aluno seleciona seu melhor texto (conto, crônica, poema ou artigo de opinião). Organização editorial: seleção, ordenação, edição, prefácio coletivo. Publicação: impressa (xerocada) ou digital (blog, PDF). Celebração da escrita como ato coletivo. O texto como permanência: deixar uma marca na escola.', ['Selecione e revise seu melhor texto do ano para a antologia.', 'Escreva uma nota biográfica de 3 linhas sobre você como autor/autora.']),
  createLesson('g2-por-b4-l8', 'L8: Linguagem e Poder — Análise Crítica Final', 'portugues', 'Reflexão final sobre linguagem e poder. Quem tem o poder de nomear a realidade? Discurso político e manipulação da linguagem. Linguagem inclusiva e representação. A escola e a língua: quem tem acesso ao poder da escrita? A Redação do ENEM como símbolo: ao escrever bem, você ganha acesso. Mas é justo que o acesso à universidade dependa de um estilo de escrita? Debate. Responsabilidade do usuário da língua: você, como falante, é ator histórico.', ['Debate: A redação do ENEM é um instrumento de inclusão ou de exclusão?', 'Como a linguagem pode ser usada como instrumento de poder e também de resistência?']),
  createLesson('g2-por-b4-l9', 'L9: Revisão Final — Todos os Conteúdos do Ano', 'portugues', 'Revisão abrangente de toda a 2ª série: Literatura (Realismo português, Simbolismo, Fernando Pessoa, vanguardas, Modernismo português, literatura africana, concretismo, ditadura, contemporâneo); Língua Portuguesa (morfossintaxe avançada, semântica, pragmática, concordância/regência/crase/colocação avançadas, estilística, análise do discurso); Produção textual (artigo de opinião, ensaio, carta aberta, redação ENEM). Quiz de revisão em grupo.', ['Participe do quiz de revisão em equipe cobrindo todos os conteúdos do ano.', 'Quais foram as 5 aprendizagens mais importantes da 2ª série para você?']),
  createLesson('g2-por-b4-l10', 'L10: Avaliação e Reflexão Final', 'portugues', 'Avaliação processual do ano: portfólio de textos produzidos, crescimento como leitor e escritor, habilidades desenvolvidas. Autoavaliação honesta: onde você estava no início do ano e onde está agora. Metas para a 3ª série: o que precisar desenvolver. A 3ª série é o ano do ENEM — o trabalho começa agora. Mensagem do professor: o que ele viu de crescimento em cada aluno. Celebração do percurso.', ['Escreva uma autoavaliação do seu desenvolvimento em Língua Portuguesa na 2ª série.', 'Quais são suas 3 metas prioritárias de Língua Portuguesa para a 3ª série?']),
  createLesson('g2-por-b4-l11', 'L11: Simulado Final Integrado', 'portugues', 'Simulado final integrado: 15 questões de Linguagens (LP) + redação completa. Simula as condições reais do ENEM. Questões de: interpretação (múltiplos gêneros), literatura (todas as escolas estudadas), gramática em contexto, figuras de linguagem, variação linguística, gêneros textuais. Redação: tema proposto com textos motivadores, 60 minutos. Balanço final do ano: como você se saiu? Você está mais preparado do que quando chegou?', ['Resolva o simulado final integrado (questões + redação).', 'Compare sua performance neste simulado com os do início do ano. Qual foi o crescimento?']),
  createLesson('g2-por-b4-l12', 'L12: Literatura e Vida — Reflexão Final', 'portugues', 'Por que ler literatura? Antonio Candido: "A literatura é um direito humano." O que a literatura faz pelo ser humano: humaniza, desperta empatia, amplia horizontes, preserva a memória coletiva, subverte a ordem, celebra a beleza. A leitura como prática de liberdade (Paulo Freire). O leitor que você se tornou. O escritor que você está se tornando. A língua portuguesa como sua mais poderosa ferramenta. Use-a com responsabilidade, criatividade e amor.', ['Escreva sobre: "O livro ou texto que mais me marcou neste ano e por quê".', 'Se você pudesse recomendar uma obra da literatura brasileira para um amigo, qual seria e por quê?']),
  createLesson('g2-por-b4-l13', 'L13: Orientação para a 3ª Série — O Ano do ENEM', 'portugues', 'Preparação para a 3ª série: o que esperar do último ano do Ensino Médio. O ENEM: estrutura, competências, áreas. Como a Língua Portuguesa é cobrada: Linguagens e Códigos (incluindo LP, Literatura, Artes, EF, Língua Estrangeira) + Redação. Cronograma sugerido: quando e como estudar ao longo da 3ª série. Vestibulares específicos: FUVEST, UNICAMP, UFT. Recursos de preparação: sites, livros, aplicativos. A preparação começa agora — não no último mês.', ['Monte um cronograma de estudos para a 3ª série com foco no ENEM.', 'Quais são os pontos de Língua Portuguesa que você ainda precisa trabalhar para o ENEM?']),
  createLesson('g2-por-b4-l14', 'L14: Encerramento e Celebração', 'portugues', 'Encerramento do ano letivo de Língua Portuguesa na 2ª série. Celebração das conquistas individuais e coletivas. Apresentação da antologia literária da turma. Reconhecimento: o aluno que mais progrediu, o melhor texto, a melhor participação. Mensagem de encerramento: você passou por um ano intenso de aprendizado. A língua portuguesa é sua identidade e sua voz. Cuide dela e deixe que ela expresse o melhor de você. Parabéns por mais um ano concluído!', ['Apresente um trecho do seu texto da antologia para a turma.', 'Escreva uma mensagem de encorajamento para um colega sobre a jornada de 3ª série que está por vir.']),
  createLesson('g2-por-b4-l15', 'L15: Projeto Interdisciplinar — Língua Portuguesa e Ciências Humanas', 'portugues', 'Conexões entre Língua Portuguesa e as disciplinas de Ciências Humanas. A linguagem na História: como os historiadores escrevem. A linguagem na Sociologia: relatórios sociais. A linguagem na Filosofia: argumentação filosófica. A linguagem na Geografia: descrição de espaços. Texto integrador: um artigo de opinião que use conhecimentos de múltiplas disciplinas. A redação do ENEM como texto interdisciplinar por natureza.', ['Escreva um artigo de opinião usando conhecimentos de História, Sociologia e LP sobre um problema social atual.', 'Como o domínio da língua portuguesa facilita o aprendizado em todas as outras disciplinas?']),
  createLesson('g2-por-b4-l16', 'L16: Língua Portuguesa e Mercado de Trabalho', 'portugues', 'A língua portuguesa como competência profissional. Comunicação oral eficaz: reuniões, apresentações, atendimento ao cliente. Escrita profissional: e-mails, relatórios, atas, currículos, cartas de apresentação. Língua e carreira: como o domínio da escrita formal influencia progressão profissional. A importância da leitura para líderes e profissionais. Em qualquer área (médico, engenheiro, professor, empresário), comunicar-se bem é diferencial. A língua como capital cultural.', ['Escreva um e-mail profissional e um currículo em português formal para uma vaga fictícia.', 'Como a língua portuguesa será importante na carreira que você pretende seguir?']),
  createLesson('g2-por-b4-l17', 'L17: Avaliação e Devolutiva Final', 'portugues', 'Encerramento formal do ano letivo. Devolutiva final do professor: crescimento observado em cada aluno. Nota final: composição ao longo do ano. Reflexão coletiva: o que a turma aprendeu junta. Recomendações para as férias: leitura, escrita espontânea, acompanhamento de notícias em português. A 3ª série começa no próximo ano — mas a preparação começa no período de férias. Boa sorte e boas leituras!', ['O que você aprendeu sobre si mesmo como leitor e escritor neste ano?', 'Qual livro você vai ler nas férias para se preparar para a 3ª série?']),
  createLesson('g2-por-b4-l18', 'L18: Revisão e Encerramento do Ano', 'portugues', 'Revisão final de todos os conteúdos do 4º Bimestre e fechamento do ano. Quiz final em equipe: perguntas sobre literatura, gramática, produção textual e interpretação. Exposição dos trabalhos finais. Entrega dos portfólios. Momento de gratidão: alunos escrevem uma mensagem de agradecimento (pode ser para o professor, para um colega, para a língua portuguesa). Fim da 2ª série — o ENEM está chegando. Você está pronto!', ['Participe do quiz final de encerramento do ano.', 'Escreva sua mensagem de agradecimento e encerramento do ano em português.']),
];
